content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以幫我點一杯紅茶嗎？",
      "pinyin": "Má fan nǐ, kě yǐ bāng wǒ diǎn yī bēi hóng chá ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 bang1 wo3 dian3 yi1 bei1 hong2 cha2 ma0?",
      "translation_en": "Excuse me, could you help me order a black tea?",
      "translation_ko": "실례합니다, 홍차 한 잔 주문하는 것을 도와주시겠어요?"
    },
    {
      "text": "不好意思，我想要一杯綠茶，半糖，可以嗎？",
      "pinyin": "Bù hǎo yì si, wǒ xiǎng yào yī bēi lǜ chá, bàn táng, kě yǐ ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, wo3 xiang3 yao4 yi1 bei1 lü4 cha2, ban4 tang2, ke3 yi3 ma0?",
      "translation_en": "Excuse me, I would like a green tea with half sugar, okay?",
      "translation_ko": "죄송합니다, 반당으로 녹차 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "店員，可以給我一個袋子嗎？謝謝。",
      "pinyin": "Diàn yuán, kě yǐ gěi wǒ yī gè dài zi ma? Xiè xie.",
      "pinyin_numeric": "dian4 yuan2, ke3 yi3 gei3 wo3 yi1 ge4 dai4 zi5 ma0? xie4 xie5.",
      "translation_en": "Shop assistant, could you give me a bag? Thank you.",
      "translation_ko": "점원님, 봉투 하나 주시겠어요? 감사합니다."
    },
    {
      "text": "請問，可以幫我加珍珠嗎？",
      "pinyin": "Qǐng wèn, kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "qing3 wen4, ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Excuse me, could you add boba for me?",
      "translation_ko": "실례합니다, 펄을 추가해 주시겠어요?"
    },
    {
      "text": "我想要一杯豆漿，去冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dòu jiāng, qù bīng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4 jiang1, qu4 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like a soy milk, no ice, okay?",
      "translation_ko": "두유 한 잔을 원하는데, 얼음 빼고 주시겠어요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？我聽不懂。",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma? Wǒ tīng bù dǒng.",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 zai4 shuo1 yi1 ci4 ma0? wo3 ting1 bu4 dong3.",
      "translation_en": "Excuse me, could you say it again? I didn't understand.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요? 못 알아들었어요."
    },
    {
      "text": "麻煩你，可以給我一個湯匙嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī gè tāng chí ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 yi1 ge4 tang1 chi2 ma0?",
      "translation_en": "Excuse me, could you give me a spoon?",
      "translation_ko": "실례합니다, 숟가락 하나 주시겠어요?"
    },
    {
      "text": "我想要一杯大杯的拿鐵，內用，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi de ná tiě, nèi yòng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 de5 na2 tie3, nei4 yong4, ke3 yi3 ma0?",
      "translation_en": "I would like a large latte, for here, okay?",
      "translation_ko": "큰 라떼 한 잔을 원하는데, 매장에서 먹을게요, 괜찮을까요?"
    },
    {
      "text": "店員，可以幫我拿發票嗎？謝謝。",
      "pinyin": "Diàn yuán, kě yǐ bāng wǒ ná fā piào ma? Xiè xie.",
      "pinyin_numeric": "dian4 yuan2, ke3 yi3 bang1 wo3 na2 fa1 piao4 ma0? xie4 xie5.",
      "translation_en": "Shop assistant, could you help me get the receipt? Thank you.",
      "translation_ko": "점원님, 영수증을 받아 주시겠어요? 감사합니다."
    }
  ]
}
